// src/lib/whisper.ts — provided by user; use verbatim
import OpenAI from 'openai';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

export async function transcribeAudio(blob: Blob): Promise<{
  text: string;
  words: { word: string; start: number; end: number }[];
}> {
  const file = new File([blob], 'audio.webm', { type: blob.type });
  const response = await openai.audio.transcriptions.create({
    file,
    model: 'whisper-1',
    response_format: 'verbose_json',
    timestamp_granularities: ['word'],
  });
  return { text: response.text, words: response.words ?? [] };
}

// src/app/api/transcribe/route.ts — provided by user; use verbatim
import { NextRequest, NextResponse } from 'next/server';
import { transcribeAudio } from '@/lib/whisper';
import { auth } from '@/lib/auth';

export async function POST(req: NextRequest) {
  const session = await auth();
  if (!session) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  const formData = await req.formData();
  const blob = formData.get('audio') as Blob;
  if (!blob) return NextResponse.json({ error: 'No audio provided' }, { status: 400 });

  const result = await transcribeAudio(blob);
  return NextResponse.json(result);
}
